import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your-project-id',
  secretKey: process.env.VEX_SECRET
});

// n8n webhook receives planning agent output
app.post('/validate-plan', async (req, res) => {
  const { query, subQueries, confidence } = req.body;

  const result = await vex.verify({
    useCase: 'agentic-rag',
    inputs: { originalQuery: query, plannedQueries: subQueries },
    checks: {
      queryPlanning: {
        maxDepth: 3,
        minCoverage: 0.8,
        preventLoops: true
      }
    }
  });

  if (result.pass) {
    res.json({ proceed: true, subQueries });
  } else {
    res.status(400).json({ error: 'Invalid query plan', issues: result.issues });
  }
});

// After vector store retriever nodes
const validateRetrievals = async (retrievals: any[]) => {
  const vex = new Vex({ /* config */ });

  const results = await Promise.all(
    retrievals.map(async (retrieval, index) => {
      return vex.verify({
        useCase: 'agentic-rag-retrieval',
        inputs: {
          subQuery: retrieval.subQuery,
          chunks: retrieval.chunks,
          metadata: retrieval.metadata
        },
        checks: {
          sourceFaithfulness: {
            threshold: 0.9,
            requireAttribution: true
          },
          hallucination: 'strict'
        }
      });
    })
  );

  return results.every(r => r.pass);
};

const checkCrossSource = async (sources: { [type: string]: any[] }) => {
  const vex = new Vex({ /* config */ });

  const result = await vex.verify({
    useCase: 'agentic-rag-consistency',
    inputs: {
      vectorChunks: sources.vector,
      sqlResults: sources.sql,
      docChunks: sources.notion
    },
    checks: {
      crossSourceConsistency: {
        semanticThreshold: 0.75,
        factAlignment: 'high',
        citationCoverage: 0.9
      }
    }
  });

  return {
    consistent: result.pass,
    citationGraph: result.citations,
    conflicts: result.issues
  };
};

// Before final response node
const verifySynthesis = async ({
  synthesis,
  sources,
  citations
}: {
  synthesis: string;
  sources: any[];
  citations: number[];
}) => {
  const vex = new Vex({ /* config */ });

  const result = await vex.verify({
    useCase: 'agentic-rag-synthesis',
    inputs: {
      response: synthesis,
      citedSources: sources.filter((_, i) => citations.includes(i)),
      allSources: sources
    },
    checks: {
      citationVerification: 'strict',
      hallucinationDetection: 'zero',
      sourceFaithfulness: 0.95
    }
  });

  return {
    verified: result.pass,
    finalResponse: result.pass ? synthesis : null,
    citationReport: result.citations
  };
};

