    "retrievals": "{{ $('Retriever').all().map(item => item.json.chunks) }}"
  },
  "checks": {
    "queryPlanning": {{ $json.planningChecks }},
    "sourceFaithfulness": {{ $json.retrievalChecks }},
    "parameterSafety": true
  }
};

// Headers
const headers = {
  "Authorization": "Bearer {{ $env.VEX_SECRET }}",
  "Content-Type": "application/json"
};

// n8n Code node before Vex webhook
const sanitizeTools = ($input) => {
  const items = $input.all();

  return items.map(item => {
    const tools = item.json.tools || [];
    const safeTools = tools.map(tool => ({
      ...tool,
      parameters: Object.fromEntries(
        Object.entries(tool.parameters || {}).map(([k, v]) => [
          k,
          typeof v === 'string' && (v.includes('sk-') || v.includes('api_key')) 
            ? '[REDACTED]' 
            : v
        ])
      )
    }));

    return {
      json: {
        ...item.json,
        tools: safeTools,
        sanitized: true
      }
    };
  });
};

return sanitizeTools($input);

